/// <summary>
/// this calss is used for the sales tax report for sales id and purchase id
/// </summary>
[DataContractAttribute]
class ETGSalesTaxinvoiceContract
{
    SalesId         salesId;
    InvoiceId       invoiceId;
}

Method.Source:
[DataMemberAttribute(" SalesId")]
public SalesId parmSalesId(SalesId _salesId = salesId)
{
     salesId = _salesId;
     return salesId;
}

[DataMemberAttribute("InvoiceId")]
public InvoiceId parmInvoiceId(InvoiceId _invoiceId = invoiceId)
{
    invoiceId = _invoiceId;
    return invoiceId;
}
